// integration_test/cart_flow_test.dart
import 'package:flutter/material.dart';
import 'package:flutter_test/flutter_test.dart';
import 'package:integration_test/integration_test.dart';
import 'package:my_app/main.dart' as app;
import 'helpers.dart';

void main() {
  IntegrationTestWidgetsFlutterBinding.ensureInitialized();

  setUp(() async {
    await wipeStorage();   // ✅ deterministic starting state
    fakeServer.reset();    // ✅ in-process fake API
    Clock.fakeNow(DateTime(2026, 1, 1)); // ✅ stable clock
  });

  testWidgets('add to cart and checkout', (tester) async {
    app.main();
    // ✅ Wait for first frame, then idle frames — never an arbitrary delay
    await tester.pumpAndSettle();

    // ✅ Find by Key, not by user-visible text — translations/format won't break it
    await tester.tap(find.byKey(const ValueKey('product-42')));
    await pumpUntilFound(tester, find.byKey(const ValueKey('add-to-cart')));
    await tester.tap(find.byKey(const ValueKey('add-to-cart')));
    await tester.pumpAndSettle();

    expect(find.byKey(const ValueKey('cart-badge-1')), findsOneWidget);
  });
}

// helpers.dart
Future<void> pumpUntilFound(
  WidgetTester t, Finder f, {
  Duration step = const Duration(milliseconds: 100),
  Duration timeout = const Duration(seconds: 10),
}) async {
  final end = DateTime.now().add(timeout);
  while (DateTime.now().isBefore(end)) {
    await t.pump(step);
    if (f.evaluate().isNotEmpty) return;
  }
  fail('timed out waiting for $f');
}

