# Play Console — staged rollout via fastlane
lane :promote do |opts|
  rollout = opts[:rollout] || '0.05'   # 5% by default
  upload_to_play_store(
    track: 'production',
    track_promote_to: nil,             # already on production from internal
    release_status: 'inProgress',      # required for staged rollouts
    rollout: rollout,
    json_key_data: ENV['PLAY_SERVICE_ACCOUNT_JSON'],
  )
end

# Halt a staged rollout immediately
lane :halt do
  upload_to_play_store(
    track: 'production',
    release_status: 'halted',
    json_key_data: ENV['PLAY_SERVICE_ACCOUNT_JSON'],
  )
end

// ── Server-side feature flag — fastest "rollback" ──
// Use a remote config (Firebase Remote Config, GrowthBook, LaunchDarkly).
class FeatureFlags {
  static Future<bool> get newCheckoutEnabled async {
    final remote = FirebaseRemoteConfig.instance;
    await remote.fetchAndActivate();
    return remote.getBool('checkout_v2_enabled');   // toggle in console = instant kill
  }
}

Widget build(BuildContext context) {
  return FutureBuilder<bool>(
    future: FeatureFlags.newCheckoutEnabled,
    builder: (_, snap) => snap.data == true
        ? const NewCheckoutFlow()
        : const LegacyCheckoutFlow(),
  );
}

